import{_ as e,o as i,c as o,a2 as s}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Versionado","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/apis-rest/05-versionado.md","filePath":"full-stack/arquitectura/apis-rest/05-versionado.md","lastUpdated":1782521464000}'),n={name:"full-stack/arquitectura/apis-rest/05-versionado.md"};function r(t,a,l,c,p,d){return i(),o("div",null,[...a[0]||(a[0]=[s(`<h1 id="versionado" tabindex="-1">Versionado <a class="header-anchor" href="#versionado" aria-label="Permalink to &quot;Versionado&quot;">​</a></h1><p>Versionar una API no consiste solo en poner <code>/v1</code>. Consiste en permitir que el contrato evolucione sin romper clientes de forma innecesaria.</p><h2 id="cambios-compatibles" tabindex="-1">Cambios compatibles <a class="header-anchor" href="#cambios-compatibles" aria-label="Permalink to &quot;Cambios compatibles&quot;">​</a></h2><p>Normalmente son compatibles:</p><ul><li>Anadir campos opcionales.</li><li>Anadir endpoints.</li><li>Anadir valores nuevos si el cliente los tolera.</li><li>Ampliar filtros opcionales.</li><li>Mejorar mensajes de error sin cambiar codigos.</li></ul><h2 id="cambios-incompatibles" tabindex="-1">Cambios incompatibles <a class="header-anchor" href="#cambios-incompatibles" aria-label="Permalink to &quot;Cambios incompatibles&quot;">​</a></h2><ul><li>Eliminar campos.</li><li>Cambiar tipos.</li><li>Cambiar significado de un campo.</li><li>Cambiar codigos de error estables.</li><li>Hacer obligatorio algo que antes era opcional.</li><li>Alterar paginacion o orden por defecto de forma visible.</li></ul><h2 id="versionado-por-url" tabindex="-1">Versionado por URL <a class="header-anchor" href="#versionado-por-url" aria-label="Permalink to &quot;Versionado por URL&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/v1/orders</span></span>
<span class="line"><span>/v2/orders</span></span></code></pre></div><p>Es simple y visible. Es el enfoque mas comun.</p><h2 id="versionado-por-header" tabindex="-1">Versionado por header <a class="header-anchor" href="#versionado-por-header" aria-label="Permalink to &quot;Versionado por header&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Accept: application/vnd.company.orders.v2+json</span></span></code></pre></div><p>Es mas flexible, pero menos visible para equipos junior y herramientas basicas.</p><h2 id="deprecacion" tabindex="-1">Deprecacion <a class="header-anchor" href="#deprecacion" aria-label="Permalink to &quot;Deprecacion&quot;">​</a></h2><p>Cuando retires una version:</p><ol><li>Anuncia fecha.</li><li>Documenta alternativa.</li><li>Mide clientes afectados.</li><li>Devuelve headers de deprecacion.</li><li>Mantiene soporte durante una ventana razonable.</li></ol><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Deprecation: true</span></span>
<span class="line"><span>Sunset: Wed, 31 Dec 2026 23:59:59 GMT</span></span></code></pre></div><h2 id="regla-practica" tabindex="-1">Regla practica <a class="header-anchor" href="#regla-practica" aria-label="Permalink to &quot;Regla practica&quot;">​</a></h2><p>Versiona cuando el contrato externo cambia de forma incompatible. No crees una version nueva por cada cambio interno.</p>`,19)])])}const h=e(n,[["render",r]]);export{m as __pageData,h as default};
